import React, { useEffect, useState } from 'react';
import '../../styles/storekeeper/storekeeper-transactions.css';
import api from '../../services/api';

const StorekeeperTransactions = () => {
  const [transactions, setTransactions] = useState([]);
  const [items, setItems] = useState([]);
  const [ponds, setPonds] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showForm, setShowForm] = useState(false);

  const [filters, setFilters] = useState({
    item_id: '',
    transaction_type: '',
    date_from: '',
    date_to: '',
  });

  const [formData, setFormData] = useState({
    item_id: '',
    transaction_type: 'IMPORT',
    quantity: '',
    unit_price: '',
    reference_type: 'PURCHASE',
    reference_id: '',
    pond_id: '',
    note: '',
  });

  useEffect(() => {
    fetchTransactions();
    fetchItems();
    fetchPonds();
  }, []);

  const fetchTransactions = async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (filters.item_id) params.append('item_id', filters.item_id);
      if (filters.transaction_type) params.append('type', filters.transaction_type);
      if (filters.date_from) params.append('date_from', filters.date_from);
      if (filters.date_to) params.append('date_to', filters.date_to);

      const res = await api.get(`/inventory/transactions?${params.toString()}`);
      setTransactions(res.data?.data || []);
      setError(null);
    } catch (err) {
      console.error('Lỗi khi tải giao dịch:', err);
      setError('Không thể tải danh sách giao dịch');
    } finally {
      setLoading(false);
    }
  };

  const fetchItems = async () => {
    try {
      const res = await api.get('/inventory/items');
      setItems(res.data?.data || []);
    } catch (err) {
      console.error('Lỗi khi tải sản phẩm:', err);
    }
  };

  const fetchPonds = async () => {
    try {
      const res = await api.get('/ponds');
      setPonds(res.data?.data || []);
    } catch (err) {
      console.error('Lỗi khi tải ao:', err);
    }
  };

  const handleFilterChange = (e) => {
    const { name, value } = e.target;
    setFilters((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleFormChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleApplyFilters = () => {
    fetchTransactions();
  };

  const handleResetFilters = () => {
    setFilters({
      item_id: '',
      transaction_type: '',
      date_from: '',
      date_to: '',
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (!formData.item_id || !formData.quantity || !formData.unit_price) {
        alert('Vui lòng nhập đầy đủ thông tin');
        return;
      }

      const payload = {
        item_id: formData.item_id,
        transaction_type: formData.transaction_type,
        quantity: formData.quantity,
        unit_price: formData.unit_price,
        reference_type: formData.reference_type,
        reference_id: formData.reference_id || null,
        pond_id: formData.pond_id || null,
        note: formData.note,
      };

      await api.post('/inventory/transactions', payload);
      alert('Tạo giao dịch thành công');
      setShowForm(false);
      resetForm();
      fetchTransactions();
      setError(null);
    } catch (err) {
      console.error('Lỗi:', err);
      setError(err.response?.data?.message || 'Không thể tạo giao dịch');
    }
  };

  const resetForm = () => {
    setFormData({
      item_id: '',
      transaction_type: 'IMPORT',
      quantity: '',
      unit_price: '',
      reference_type: 'PURCHASE',
      reference_id: '',
      pond_id: '',
      note: '',
    });
  };

  const handleCloseForm = () => {
    setShowForm(false);
    resetForm();
  };

  const getTransactionTypeLabel = (type) => (type === 'IMPORT' ? '📥 Nhập kho' : '📤 Xuất kho');

  const getReferenceTypeLabel = (type) => {
    const labels = {
      FEED_LOG: 'Nhật ký cho ăn',
      CULTIVATION_LOG: 'Nhật ký canh tác',
      PURCHASE: 'Mua hàng',
      RETURN: 'Trả hàng',
    };
    return labels[type] || type;
  };

  return (
    <div className="storekeeper-transactions__page">
      <div className="storekeeper-transactions__header">
        <h1>Giao dịch xuất/nhập kho</h1>
        <p>Ghi nhận lịch sử nhập xuất hàng hóa</p>
      </div>

      {error && (
        <div className="storekeeper-transactions__error">
          <p>{error}</p>
        </div>
      )}

      <div className="storekeeper-transactions__filters">
        <select
          name="item_id"
          value={filters.item_id}
          onChange={handleFilterChange}
          className="storekeeper-transactions__filter"
        >
          <option value="">Tất cả sản phẩm</option>
          {items.map((item) => (
            <option key={item.item_id} value={item.item_id}>
              {item.item_code} - {item.item_name}
            </option>
          ))}
        </select>

        <select
          name="transaction_type"
          value={filters.transaction_type}
          onChange={handleFilterChange}
          className="storekeeper-transactions__filter"
        >
          <option value="">Tất cả loại giao dịch</option>
          <option value="IMPORT">📥 Nhập kho</option>
          <option value="EXPORT">📤 Xuất kho</option>
        </select>

        <input
          type="date"
          name="date_from"
          value={filters.date_from}
          onChange={handleFilterChange}
          className="storekeeper-transactions__filter"
        />

        <input
          type="date"
          name="date_to"
          value={filters.date_to}
          onChange={handleFilterChange}
          className="storekeeper-transactions__filter"
        />

        <button onClick={handleApplyFilters} className="storekeeper-transactions__button-primary">
          🔍 Tìm kiếm
        </button>

        <button onClick={handleResetFilters} className="storekeeper-transactions__button-secondary">
          🔄 Làm mới
        </button>

        <button onClick={() => setShowForm(true)} className="storekeeper-transactions__button-primary">
          ➕ Tạo giao dịch
        </button>
      </div>

      {showForm && (
        <div className="storekeeper-transactions__modal">
          <div className="storekeeper-transactions__modal-content">
            <div className="storekeeper-transactions__modal-header">
              <h2>Tạo giao dịch mới</h2>
              <button onClick={handleCloseForm} className="storekeeper-transactions__close-btn">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="storekeeper-transactions__form">
              <div className="storekeeper-transactions__form-group">
                <label>Sản phẩm *</label>
                <select name="item_id" value={formData.item_id} onChange={handleFormChange} required>
                  <option value="">Chọn sản phẩm</option>
                  {items.map((item) => (
                    <option key={item.item_id} value={item.item_id}>
                      {item.item_code} - {item.item_name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="storekeeper-transactions__form-row">
                <div className="storekeeper-transactions__form-group">
                  <label>Loại giao dịch *</label>
                  <select name="transaction_type" value={formData.transaction_type} onChange={handleFormChange} required>
                    <option value="IMPORT">📥 Nhập kho</option>
                    <option value="EXPORT">📤 Xuất kho</option>
                  </select>
                </div>

                <div className="storekeeper-transactions__form-group">
                  <label>Số lượng *</label>
                  <input
                    type="number"
                    name="quantity"
                    value={formData.quantity}
                    onChange={handleFormChange}
                    placeholder="0"
                    step="0.01"
                    required
                  />
                </div>
              </div>

              <div className="storekeeper-transactions__form-row">
                <div className="storekeeper-transactions__form-group">
                  <label>Đơn giá *</label>
                  <input
                    type="number"
                    name="unit_price"
                    value={formData.unit_price}
                    onChange={handleFormChange}
                    placeholder="0"
                    step="0.01"
                    required
                  />
                </div>

                <div className="storekeeper-transactions__form-group">
                  <label>Loại tham chiếu</label>
                  <select name="reference_type" value={formData.reference_type} onChange={handleFormChange}>
                    <option value="PURCHASE">Mua hàng</option>
                    <option value="FEED_LOG">Nhật ký cho ăn</option>
                    <option value="CULTIVATION_LOG">Nhật ký canh tác</option>
                    <option value="RETURN">Trả hàng</option>
                  </select>
                </div>
              </div>

              <div className="storekeeper-transactions__form-group">
                <label>ID tham chiếu</label>
                <input
                  type="text"
                  name="reference_id"
                  value={formData.reference_id}
                  onChange={handleFormChange}
                  placeholder="VD: Feed Log ID hoặc Cultivation Log ID"
                />
              </div>

              <div className="storekeeper-transactions__form-group">
                <label>Ao</label>
                <select name="pond_id" value={formData.pond_id} onChange={handleFormChange}>
                  <option value="">Chọn ao (tuỳ chọn)</option>
                  {ponds.map((pond) => (
                    <option key={pond.pond_id} value={pond.pond_id}>
                      {pond.pond_code} - {pond.pond_name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="storekeeper-transactions__form-group">
                <label>Ghi chú</label>
                <textarea
                  name="note"
                  value={formData.note}
                  onChange={handleFormChange}
                  placeholder="Ghi chú thêm về giao dịch"
                  rows="3"
                ></textarea>
              </div>

              <div className="storekeeper-transactions__modal-actions">
                <button type="submit" className="storekeeper-transactions__button-primary">
                  ✓ Tạo giao dịch
                </button>
                <button type="button" onClick={handleCloseForm} className="storekeeper-transactions__button-secondary">
                  ✕ Hủy
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {loading ? (
        <div className="storekeeper-transactions__loading">Đang tải...</div>
      ) : (
        <div className="storekeeper-transactions__table-wrapper">
          <table className="storekeeper-transactions__table">
            <thead>
              <tr>
                <th>Ngày</th>
                <th>Mã sản phẩm</th>
                <th>Loại giao dịch</th>
                <th>Số lượng</th>
                <th>Đơn giá</th>
                <th>Tổng tiền</th>
                <th>Ao</th>
                <th>Loại tham chiếu</th>
                <th>Người tạo</th>
              </tr>
            </thead>
            <tbody>
              {transactions.length > 0 ? (
                transactions.map((trans) => (
                  <tr key={trans.transaction_id}>
                    <td>{new Date(trans.created_at).toLocaleDateString('vi-VN')}</td>
                    <td className="storekeeper-transactions__code">{trans.item_code}</td>
                    <td>
                      <span className={`storekeeper-transactions__type storekeeper-transactions__type--${trans.transaction_type.toLowerCase()}`}>
                        {getTransactionTypeLabel(trans.transaction_type)}
                      </span>
                    </td>
                    <td className="storekeeper-transactions__quantity">
                      {parseFloat(trans.quantity).toFixed(2)} {trans.unit}
                    </td>
                    <td>{parseFloat(trans.unit_price || 0).toLocaleString('vi-VN')} VNĐ</td>
                    <td className="storekeeper-transactions__amount">
                      {parseFloat(trans.total_amount || 0).toLocaleString('vi-VN')} VNĐ
                    </td>
                    <td>{trans.pond_code || '—'}</td>
                    <td>{getReferenceTypeLabel(trans.reference_type)}</td>
                    <td>{trans.created_by_name}</td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="9" className="storekeeper-transactions__empty">
                    Không tìm thấy giao dịch nào
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default StorekeeperTransactions;
